// Localiza o primeiro binário .xlsx/.xls/.csv recebido pelo Webhook.
// O n8n nomeia arquivos multipart como data0, data1, ... (com binaryPropertyName=data).
// Renomeia para 'data0' para alimentar o nó Update File com nome estável.
const item = $input.first();
const bin = item.binary || {};
const keys = Object.keys(bin);

if (keys.length === 0) {
  throw new Error('Nenhum arquivo recebido. Envie um .xlsx no campo do form-data.');
}

// Pega o primeiro binário (data0 normalmente).
const sourceKey = keys[0];
const fileBin = bin[sourceKey];
const fileName = (fileBin.fileName || '').toLowerCase();
const mime = (fileBin.mimeType || '').toLowerCase();

const valid = fileName.endsWith('.xlsx') || fileName.endsWith('.xls') || fileName.endsWith('.csv')
  || mime.includes('spreadsheetml') || mime.includes('excel') || mime.includes('csv');

if (!valid) {
  throw new Error(`Arquivo inválido: ${fileBin.fileName || sourceKey}. Envie .xlsx, .xls ou .csv.`);
}

// Campos de texto do form-data (mês de referência), se enviados pelo front.
const body = item.json && item.json.body ? item.json.body : (item.json || {});
const periodo = body.periodo || null;  // YYYY-MM
const rotulo = body.rotulo || null;    // ex.: 'Junho/2026'

return [{
  json: {
    received_file: fileBin.fileName,
    mime: fileBin.mimeType,
    size_bytes: fileBin.fileSize || null,
    periodo,
    rotulo
  },
  binary: { data0: fileBin }
}];

// Gate de esquema: valida a planilha recebida ANTES de substituir a oficial.
// Exige EXATAMENTE as 22 colunas padrão da aba "Base e QC".
// NÃO lança erro: marca _schema_ok para o nó IF ramificar e responder ao front.
const EXPECTED = ['#','Loja','Index','ID do Anúncio','Nome do Anúncio','Impressões','Cliques','CTR','Conversões','Custo por Conversão','Taxa de Conversão','Itens Vendidos','GMV','Despesas','ACOS','Categoria','Tamanho','Qtd','% Lucro Médio P','lucro liquido','% Lucro','Índice'];
const norm = s => String(s == null ? '' : s).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
const isJunk = c => { const n = norm(c); return n === '' || /^__empty/.test(n); };
const orig = $('Validar Arquivo').first();
const linhas = $input.all();
let erro = null;
if (linhas.length === 0) {
  erro = 'Planilha fora do padrão: não foi possível ler a aba principal (esperado "Base e QC" com 22 colunas). Verifique se enviou a planilha correta.';
} else {
  const colsRaw = Object.keys(linhas[0].json || {}).filter(c => !isJunk(c));
  const colsNorm = colsRaw.map(norm);
  const expNorm = EXPECTED.map(norm);
  const faltando = EXPECTED.filter((c, i) => !colsNorm.includes(expNorm[i]));
  const extras = colsRaw.filter(c => !expNorm.includes(norm(c)));
  if (faltando.length > 0 || extras.length > 0 || colsNorm.length !== expNorm.length) {
    erro = ['Planilha fora do padrão — upload BLOQUEADO (a planilha oficial NÃO foi alterada).', 'Esperado: aba "Base e QC" com exatamente 22 colunas.', 'Faltando (' + faltando.length + '): ' + (faltando.length ? faltando.join(', ') : 'nenhuma'), 'Inesperadas (' + extras.length + '): ' + (extras.length ? extras.join(', ') : 'nenhuma'), 'Recebidas (' + colsRaw.length + '): ' + colsRaw.join(', ')].join(' | ');
  }
}
if (erro) {
  return [{ json: { _schema_ok: false, _erro: erro } }];
}
// OK: repassa o item ORIGINAL (com binário data0 + periodo/rotulo) marcando a flag.
return [{ json: Object.assign({}, orig.json, { _schema_ok: true }), binary: orig.binary }];

// Decide se o upload pode substituir a base do agente no Drive.
// Regra: só substitui se a data enviada for >= à mais recente já registrada.
// Datas anteriores vão APENAS para o histórico (não tocam no Drive).
const meta = $('Validar Arquivo').first();
const m = meta.json || {};
let periodo = m.periodo || null;
if (!periodo) { throw new Error('periodo ausente no upload — data de referência obrigatória.'); }
const pData = /^\d{4}-\d{2}$/.test(periodo) ? (periodo + '-01') : String(periodo).slice(0, 10);
const maxData = String($json.max_periodo || '1900-01-01').slice(0, 10);
const atualizar_drive = pData >= maxData;
return [{ json: Object.assign({}, m, { periodo, periodo_data: pData, max_periodo: maxData, atualizar_drive }), binary: meta.binary }];

// Monta as linhas do ARQUIVO ENVIADO para a captura (sem ler o Drive).
// Marca cada linha com _modo='rows_diretas' para o sub-fluxo consolidar
// exatamente os dados desta planilha — garante o snapshot correto da data,
// inclusive para uploads retroativos que NÃO atualizam o Drive.
const rows = $('Extrair Planilha (validação)').all().map(i => i.json);
if (rows.length === 0) {
  throw new Error('Arquivo sem linhas para captura de snapshot.');
}
return rows.map(r => ({ json: Object.assign({ _modo: 'rows_diretas' }, r) }));

// O sub-fluxo retorna o SUMARIO_PRE_CALCULADO como primeiro item.
// Localiza o objeto que contém produtos[] (independente do wrapper).
let sumario = null;
for (const it of $input.all()) {
  const j = it.json || {};
  // GUARDA: se o sub-fluxo devolveu a LISTA DE ABAS, a aba configurada não existe.
  // Falha com mensagem clara em vez de capturar vazio silenciosamente.
  if (Array.isArray(j.abas_disponiveis)) {
    throw new Error('Sub-fluxo retornou a lista de abas em vez dos dados. A aba configurada em "Obter Sumário" (nome_do_separador) não existe na planilha. Abas disponíveis: ' + j.abas_disponiveis.join(', ') + '. Ajuste o parametro nome_do_separador para uma destas.');
  }
  if (Array.isArray(j.produtos)) { sumario = j; break; }
  if (j.__tipo === 'SUMARIO_PRE_CALCULADO' && Array.isArray(j.produtos)) { sumario = j; break; }
  if (j.json && Array.isArray(j.json.produtos)) { sumario = j.json; break; }
}

if (!sumario || !Array.isArray(sumario.produtos)) {
  // Não bloqueia o upload: apenas sinaliza que não houve captura.
  return [{ json: { _capturar: false, motivo: 'SUMARIO_PRE_CALCULADO sem produtos[]' } }];
}

const meta = $('Validar Arquivo').first().json || {};
const fileName = meta.received_file || null;
const periodo = meta.periodo || null;
const rotulo = meta.rotulo || null;

// Falhar cedo: NUNCA seguir sem a data de referência.
if (!periodo) {
  throw new Error('periodo ausente no upload — data de referência obrigatória.');
}

// Falhar cedo: planilha lida vazia (0 produtos).
if (sumario.produtos.length === 0) {
  throw new Error('Captura abortada: a planilha foi lida com 0 produtos (total_anuncios=' + (sumario.total_anuncios ?? 0) + '). Verifique o arquivo enviado.');
}

return [{
  json: {
    _capturar: true,
    produtos: sumario.produtos,
    arquivo_nome: fileName,
    periodo: periodo,
    rotulo: rotulo,
    user_id: null
  }
}];
